        // then - deleteByUserId → deleteByUserId → save 순서 보장
        val inOrder = inOrder(queueRepository, callRoomRepository)
        inOrder.verify(queueRepository).deleteByUserId("user-A")
        inOrder.verify(queueRepository).deleteByUserId("user-B")
