package com.maum.backend.call.service

import com.maum.backend.call.domain.*
import com.maum.backend.call.repository.CallMatchingQueueRepository
import com.maum.backend.call.repository.CallRoomRepository
import com.maum.backend.call.repository.UserBlockRepository
import org.springframework.stereotype.Service
import java.time.Instant

/**
 * 음성 통화 매칭 서비스
 *
 * 매칭 흐름:
 * 1. 유저가 매칭 큐에 진입 (enqueue)
 * 2. 적합한 파트너 탐색 (findMatchablePartner)
 * 3. 매칭 성공 시 CallRoom 생성 (createRoom)
 * 4. 매칭 실패 또는 취소 시 큐에서 제거 (dequeue)
 */
@Service
class CallMatchingService(
    private val queueRepository: CallMatchingQueueRepository,
    private val callRoomRepository: CallRoomRepository,
    private val userBlockRepository: UserBlockRepository,
) {
    companion object {
        const val MAX_QUEUE_WAIT_SECONDS = 300L  // 5분 대기 제한
    }

    /**
     * 유저를 매칭 큐에 등록
     * - 이미 큐에 있거나, 통화 중이면 예외
     * - 성별/나이 필터 조건 포함
     */
    fun enqueue(request: MatchingRequest): MatchingQueueEntry {
        val userId = request.userId

        // 중복 큐 진입 방지
        if (queueRepository.existsByUserId(userId)) {
            throw AlreadyInQueueException("유저($userId)가 이미 대기열에 있습니다.")
        }

        // 이미 통화 중인 경우 방지
        if (callRoomRepository.existsActiveRoomByUserId(userId)) {
            throw UserAlreadyInCallException("유저($userId)가 이미 통화 중입니다.")
        }

        val entry = MatchingQueueEntry(
            userId = userId,
            gender = request.gender,
            preferredGender = request.preferredGender,
            ageRange = request.ageRange,
            enqueuedAt = Instant.now(),
        )
        return queueRepository.save(entry)
    }

    /**
     * 매칭 시도: 큐에서 상대방을 찾아 CallRoom 생성
     * - 성별 선호도 매칭
     * - 나이 범위 교차 확인
     * - 차단 유저 제외
     * - 대기 시간 초과 항목 자동 제거
     */
    fun tryMatch(userId: String): MatchResult {
        val myEntry = queueRepository.findByUserId(userId)
            ?: throw NotInQueueException("유저($userId)가 대기열에 없습니다.")

        // 대기 시간 초과 검사
        if (isWaitExpired(myEntry)) {
            queueRepository.deleteByUserId(userId)
            throw MatchingTimeoutException("매칭 대기 시간이 초과되었습니다.")
        }

        // 차단 목록 로드
        val blockedByMe = userBlockRepository.findBlockedUserIdsByBlocker(userId).toSet()
        val blockedMe = userBlockRepository.findBlockerIdsByBlockedUser(userId).toSet()
        val excludeUserIds = blockedByMe + blockedMe + setOf(userId)

        // 적합한 파트너 탐색
        val partner = queueRepository.findMatchablePartner(
            myEntry = myEntry,
            excludeUserIds = excludeUserIds,
        ) ?: return MatchResult.Pending

        // 두 항목 큐에서 제거 후 방 생성 (원자적으로 처리해야 하지만 여기선 순서 보장)
        queueRepository.deleteByUserId(userId)
        queueRepository.deleteByUserId(partner.userId)

        val room = callRoomRepository.save(
            CallRoom(
                participantIds = listOf(userId, partner.userId),
                createdAt = Instant.now(),
                status = CallRoomStatus.ACTIVE,
            )
        )

        return MatchResult.Matched(room)
    }

    /**
     * 매칭 큐에서 나가기 (취소)
     */
    fun dequeue(userId: String) {
        if (!queueRepository.existsByUserId(userId)) {
            throw NotInQueueException("유저($userId)가 대기열에 없습니다.")
        }
        queueRepository.deleteByUserId(userId)
    }

    private fun isWaitExpired(entry: MatchingQueueEntry): Boolean {
        val waitSeconds = Instant.now().epochSecond - entry.enqueuedAt.epochSecond
        return waitSeconds > MAX_QUEUE_WAIT_SECONDS
    }
}

