import com.maum.backend.call.repository.CallRoomRepository
import com.maum.backend.call.repository.UserBlockRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.*
import org.mockito.junit.jupiter.MockitoExtension
import java.time.Instant

/**
 * CallMatchingService 단위 테스트
 *
 * 커버하는 엣지 케이스:
 * 1. enqueue - 중복 진입, 통화 중 진입
 * 2. tryMatch - 정상 매칭, 파트너 없음(Pending), 대기 시간 초과,
 *               차단 유저 제외, 미등록 유저, 양방향 차단
 * 3. dequeue  - 정상 취소, 큐에 없는 유저 취소
 */
@ExtendWith(MockitoExtension::class)
class CallMatchingServiceTest {

    @Mock
    private lateinit var queueRepository: CallMatchingQueueRepository

    @Mock
    private lateinit var callRoomRepository: CallRoomRepository

    @Mock
    private lateinit var userBlockRepository: UserBlockRepository

    @InjectMocks
    private lateinit var service: CallMatchingService

    // ─────────────────────────────────────────────────────────
    // enqueue
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should enqueue user successfully when not in queue and not in call`() {
        // given
        val request = matchingRequest(userId = "user-A")
        `when`(queueRepository.existsByUserId("user-A")).thenReturn(false)
        `when`(callRoomRepository.existsActiveRoomByUserId("user-A")).thenReturn(false)
        val savedEntry = queueEntry(userId = "user-A")
        `when`(queueRepository.save(any())).thenReturn(savedEntry)

        // when
        val result = service.enqueue(request)

        // then
        assertThat(result.userId).isEqualTo("user-A")
        verify(queueRepository).save(any())
    }

    @Test
    fun `should throw AlreadyInQueueException when user is already in queue`() {
        // given
        val request = matchingRequest(userId = "user-A")
        `when`(queueRepository.existsByUserId("user-A")).thenReturn(true)

        // when & then
        assertThrows<AlreadyInQueueException> {
            service.enqueue(request)
        }
        verify(queueRepository, never()).save(any())
    }

    @Test
    fun `should throw UserAlreadyInCallException when user is already in active call`() {
        // given
        val request = matchingRequest(userId = "user-A")
        `when`(queueRepository.existsByUserId("user-A")).thenReturn(false)
        `when`(callRoomRepository.existsActiveRoomByUserId("user-A")).thenReturn(true)

        // when & then
        assertThrows<UserAlreadyInCallException> {
            service.enqueue(request)
        }
        verify(queueRepository, never()).save(any())
    }

    // ─────────────────────────────────────────────────────────
    // tryMatch - 정상 매칭
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should return Matched result when partner is found in queue`() {
        // given
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())
        val partnerEntry = queueEntry(userId = "user-B", enqueuedAt = recentTime())
        val room = CallRoom(
            participantIds = listOf("user-A", "user-B"),
            createdAt = Instant.now(),
            status = CallRoomStatus.ACTIVE,
        )

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(emptyList())
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(emptyList())
        `when`(queueRepository.findMatchablePartner(eq(myEntry), any())).thenReturn(partnerEntry)
        `when`(callRoomRepository.save(any())).thenReturn(room)

        // when
        val result = service.tryMatch("user-A")

        // then
        assertThat(result).isInstanceOf(MatchResult.Matched::class.java)
        val matched = result as MatchResult.Matched
        assertThat(matched.room.participantIds).containsExactlyInAnyOrder("user-A", "user-B")

        // 두 유저 모두 큐에서 제거됐는지 확인
        verify(queueRepository).deleteByUserId("user-A")
        verify(queueRepository).deleteByUserId("user-B")
        verify(callRoomRepository).save(any())
    }

    @Test
    fun `should return Pending when no matchable partner exists in queue`() {
        // given
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(emptyList())
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(emptyList())
        `when`(queueRepository.findMatchablePartner(eq(myEntry), any())).thenReturn(null)

        // when
        val result = service.tryMatch("user-A")

        // then
        assertThat(result).isEqualTo(MatchResult.Pending)
        verify(queueRepository, never()).deleteByUserId(any())
        verify(callRoomRepository, never()).save(any())
    }

    // ─────────────────────────────────────────────────────────
    // tryMatch - 엣지 케이스: 대기 시간 초과
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should throw MatchingTimeoutException and remove from queue when wait time exceeded`() {
        // given - enqueuedAt이 MAX_QUEUE_WAIT_SECONDS 초 이상 전
        val expiredEntry = queueEntry(
            userId = "user-A",
            enqueuedAt = Instant.now().minusSeconds(CallMatchingService.MAX_QUEUE_WAIT_SECONDS + 1),
        )
        `when`(queueRepository.findByUserId("user-A")).thenReturn(expiredEntry)

        // when & then
        assertThrows<MatchingTimeoutException> {
            service.tryMatch("user-A")
        }

        // 큐에서 자동 제거
        verify(queueRepository).deleteByUserId("user-A")
        verify(queueRepository, never()).findMatchablePartner(any(), any())
        verify(callRoomRepository, never()).save(any())
    }

    @Test
    fun `should not timeout when wait time is exactly at boundary`() {
        // given - 정확히 MAX_QUEUE_WAIT_SECONDS 전 (경계값: 초과가 아님)
        val boundaryEntry = queueEntry(
            userId = "user-A",
            enqueuedAt = Instant.now().minusSeconds(CallMatchingService.MAX_QUEUE_WAIT_SECONDS),
        )
        `when`(queueRepository.findByUserId("user-A")).thenReturn(boundaryEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(emptyList())
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(emptyList())
        `when`(queueRepository.findMatchablePartner(any(), any())).thenReturn(null)

        // when - timeout 예외가 아닌 Pending 반환
        val result = service.tryMatch("user-A")

        // then
        assertThat(result).isEqualTo(MatchResult.Pending)
    }

    // ─────────────────────────────────────────────────────────
    // tryMatch - 엣지 케이스: 차단 유저 제외
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should exclude blocked users when finding matchable partner`() {
        // given
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())
        val blockedByMe = listOf("user-X", "user-Y")
        val blockedMe = listOf("user-Z")

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(blockedByMe)
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(blockedMe)
        `when`(queueRepository.findMatchablePartner(any(), any())).thenReturn(null)

        // when
        service.tryMatch("user-A")

        // then - excludeUserIds에 차단 유저 + 자기 자신이 포함돼야 함
        verify(queueRepository).findMatchablePartner(
            eq(myEntry),
            argThat { excludeIds ->
                excludeIds.containsAll(setOf("user-X", "user-Y", "user-Z", "user-A"))
            },
        )
    }

    @Test
    fun `should exclude self from matchable candidates`() {
        // given - 차단 목록이 비어있어도 자기 자신은 항상 제외
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(emptyList())
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(emptyList())
        `when`(queueRepository.findMatchablePartner(any(), any())).thenReturn(null)

        // when
        service.tryMatch("user-A")

        // then
        verify(queueRepository).findMatchablePartner(
            eq(myEntry),
            argThat { excludeIds -> excludeIds.contains("user-A") },
        )
    }

    @Test
    fun `should handle bidirectional block correctly`() {
        // given - user-A가 user-B를 차단하고 user-C가 user-A를 차단한 경우
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(listOf("user-B"))
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(listOf("user-C"))
        `when`(queueRepository.findMatchablePartner(any(), any())).thenReturn(null)

        // when
        service.tryMatch("user-A")

        // then - user-B와 user-C 모두 제외
        verify(queueRepository).findMatchablePartner(
            eq(myEntry),
            argThat { excludeIds ->
                excludeIds.containsAll(setOf("user-A", "user-B", "user-C"))
            },
        )
    }

    // ─────────────────────────────────────────────────────────
    // tryMatch - 엣지 케이스: 큐에 없는 유저
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should throw NotInQueueException when user is not in queue during tryMatch`() {
        // given
        `when`(queueRepository.findByUserId("user-A")).thenReturn(null)

        // when & then
        assertThrows<NotInQueueException> {
            service.tryMatch("user-A")
        }

        verify(userBlockRepository, never()).findBlockedUserIdsByBlocker(any())
        verify(queueRepository, never()).findMatchablePartner(any(), any())
    }

    // ─────────────────────────────────────────────────────────
    // dequeue
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should dequeue user successfully when user is in queue`() {
        // given
        `when`(queueRepository.existsByUserId("user-A")).thenReturn(true)

        // when
        service.dequeue("user-A")

        // then
        verify(queueRepository).deleteByUserId("user-A")
    }

    @Test
    fun `should throw NotInQueueException when dequeuing user not in queue`() {
        // given
        `when`(queueRepository.existsByUserId("user-A")).thenReturn(false)

        // when & then
        assertThrows<NotInQueueException> {
            service.dequeue("user-A")
        }
        verify(queueRepository, never()).deleteByUserId(any())
    }

    // ─────────────────────────────────────────────────────────
    // 엣지 케이스: 매칭 성공 후 CallRoom 상태 검증
    // ─────────────────────────────────────────────────────────

    @Test
    fun `should create CallRoom with ACTIVE status when match succeeds`() {
        // given
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())
        val partnerEntry = queueEntry(userId = "user-B", enqueuedAt = recentTime())

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(emptyList())
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(emptyList())
        `when`(queueRepository.findMatchablePartner(eq(myEntry), any())).thenReturn(partnerEntry)

        val savedRoom = CallRoom(
            participantIds = listOf("user-A", "user-B"),
            createdAt = Instant.now(),
            status = CallRoomStatus.ACTIVE,
        )
        `when`(callRoomRepository.save(any())).thenReturn(savedRoom)

        // when
        val result = service.tryMatch("user-A")

        // then
        val matched = result as MatchResult.Matched
        assertThat(matched.room.status).isEqualTo(CallRoomStatus.ACTIVE)
        assertThat(matched.room.participantIds).hasSize(2)
    }

    @Test
    fun `should remove both users from queue atomically when match succeeds`() {
        // given
        val myEntry = queueEntry(userId = "user-A", enqueuedAt = recentTime())
        val partnerEntry = queueEntry(userId = "user-B", enqueuedAt = recentTime())

        `when`(queueRepository.findByUserId("user-A")).thenReturn(myEntry)
        `when`(userBlockRepository.findBlockedUserIdsByBlocker("user-A")).thenReturn(emptyList())
        `when`(userBlockRepository.findBlockerIdsByBlockedUser("user-A")).thenReturn(emptyList())
        `when`(queueRepository.findMatchablePartner(eq(myEntry), any())).thenReturn(partnerEntry)
        `when`(callRoomRepository.save(any())).thenReturn(
            CallRoom(
                participantIds = listOf("user-A", "user-B"),
                createdAt = Instant.now(),
                status = CallRoomStatus.ACTIVE,
            )
        )

        // when
        service.tryMatch("user-A")

        // then - 매칭 성공 시 양쪽 모두 큐에서 제거 필수
        val inOrder = inOrder(queueRepository, callRoomRepository)
        inOrder.verify(queueRepository).deleteByUserId("user-A")
        inOrder.verify(queueRepository).deleteByUserId("user-B")
        inOrder.verify(callRoomRepository).save(any())
    }

    // ─────────────────────────────────────────────────────────
    // 헬퍼 함수
    // ─────────────────────────────────────────────────────────

    private fun matchingRequest(
        userId: String = "user-A",
        gender: Gender = Gender.MALE,
        preferredGender: Gender? = Gender.FEMALE,
        ageRange: IntRange = 20..30,
    ) = MatchingRequest(
        userId = userId,
        gender = gender,
        preferredGender = preferredGender,
        ageRange = ageRange,
    )

    private fun queueEntry(
        userId: String = "user-A",
        gender: Gender = Gender.MALE,
        preferredGender: Gender? = Gender.FEMALE,
        ageRange: IntRange = 20..30,
        enqueuedAt: Instant = recentTime(),
    ) = MatchingQueueEntry(
        userId = userId,
        gender = gender,
        preferredGender = preferredGender,
        ageRange = ageRange,
        enqueuedAt = enqueuedAt,
    )

    /** 방금 큐에 진입한 시각 (타임아웃 미발생) */
    private fun recentTime(): Instant = Instant.now().minusSeconds(10)
}
